import * as XLSX from 'xlsx';
import { SheetData, MergedData } from '../types';

export const parseExcelFile = async (file: File): Promise<SheetData[]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();

    reader.onload = (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'binary' });

        const sheets: SheetData[] = [];

        workbook.SheetNames.forEach(sheetName => {
          const worksheet = workbook.Sheets[sheetName];
          // Convert sheet to JSON
          const jsonData = XLSX.utils.sheet_to_json(worksheet, { header: 1 });

          if (jsonData.length > 0) {
            const header = jsonData[0] as string[];
            // Convert rest to objects based on header
            const rows = XLSX.utils.sheet_to_json(worksheet);

            sheets.push({
              name: sheetName,
              data: rows,
              header: header
            });
          }
        });

        resolve(sheets);
      } catch (error) {
        reject(error);
      }
    };

    reader.onerror = (error) => reject(error);
    reader.readAsBinaryString(file);
  });
};

export const mergeSheets = (sheets: SheetData[]): MergedData => {
  // 1. Collect all unique headers from all sheets
  const allHeaders = new Set<string>();
  sheets.forEach(sheet => {
    sheet.header.forEach(h => allHeaders.add(h));
  });

  const mergedHeaders = Array.from(allHeaders);

  // 2. Combine all rows, adding a "_SourceSheet" column for traceability
  let mergedRows: any[] = [];

  sheets.forEach(sheet => {
    const rowsWithSource = sheet.data.map(row => ({
      ...row,
      _SourceSheet: sheet.name // Add metadata column
    }));
    mergedRows = [...mergedRows, ...rowsWithSource];
  });

  // Ensure _SourceSheet is in headers
  if (!mergedHeaders.includes('_SourceSheet')) {
    mergedHeaders.unshift('_SourceSheet');
  }

  return {
    headers: mergedHeaders,
    rows: mergedRows
  };
};

export const exportToCSV = (data: MergedData, filename: string) => {
  const ws = XLSX.utils.json_to_sheet(data.rows, { header: data.headers });
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, "MergedData");
  XLSX.writeFile(wb, `${filename}_merged.csv`);
};

import { GoogleGenAI } from "@google/genai";
import { MergedData } from "../types";

const initGenAI = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found");
  }
  return new GoogleGenAI({ apiKey });
};

export const analyzeDataset = async (data: MergedData): Promise<string> => {
  try {
    const ai = initGenAI();

    // Prepare a sample of the data to avoid token limits
    // Take headers and first 10 rows + 5 random rows from middle
    const sampleRows = data.rows.slice(0, 10);
    const middleIndex = Math.floor(data.rows.length / 2);
    const randomRows = data.rows.slice(middleIndex, middleIndex + 5);

    const contextData = {
      totalRows: data.rows.length,
      headers: data.headers,
      sampleData: [...sampleRows, ...randomRows]
    };

    const prompt = `
      I have merged multiple Excel sheets into one dataset. 
      Here is a sample of the data in JSON format:
      \`\`\`json
      ${JSON.stringify(contextData, null, 2)}
      \`\`\`

      Please provide a concise analysis of this dataset.
      1. Identify what this data likely represents (Sales, Inventory, user logs, etc.).
      2. Point out any potential data quality issues visible in the sample (missing fields, inconsistent formatting).
      3. Suggest 3 key insights or questions a user might want to answer with this data.

      Keep the tone professional and helpful. Format using Markdown.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: "You are an expert Data Analyst helping a user understand their merged spreadsheet data.",
      }
    });

    return response.text || "No analysis generated.";
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    return "Failed to generate analysis. Please try again or check your API key.";
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost';
  isLoading?: boolean;
  icon?: React.ReactNode;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  icon,
  className = '',
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center px-4 py-2 rounded-lg font-medium transition-all focus:outline-none focus:ring-2 focus:ring-offset-2 disabled:opacity-50 disabled:cursor-not-allowed";

